import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import { PaymentRequest } from 'react-native-payments';

const paymentProviders = {
  applePay: 'apple-pay',
  googlePay: 'google-pay',
};

const PaymentModule = () => {
  const [selectedProvider, setSelectedProvider] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState(null);

  const handleSelectProvider = (provider) => {
    setSelectedProvider(provider);
  };

  const handleMakePayment = async () => {
    if (!selectedProvider || !paymentMethod) return;

    try {
      const paymentRequest = new PaymentRequest({
        provider: selectedProvider,
        amount: 10.99,
        currencyCode: 'USD',
        paymentMethod: paymentMethod,
      });

      const result = await paymentRequest.makePayment();
      console.log(result);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Text>Payment Module</Text>

      {Object.keys(paymentProviders).map((provider, index) => (
        <Button
          key={index}
          title={`Select ${provider}`}
          onPress={() => handleSelectProvider(provider)}
        />
      ))}

      {selectedProvider && (
        <View>
          <Text>Selected Provider: {selectedProvider}</Text>

          <Button
            title="Make Payment"
            onPress={handleMakePayment}
          />

          {paymentMethod && (
            <Text>Payment Method: {paymentMethod}</Text>
          )}
        </View>
      )}
    </View>
  );
};

export default PaymentModule;